# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
import os
import time

app = Flask(__name__)

es = Elasticsearch(
    [os.getenv('ELASTICSEARCH_HOST', 'localhost:9200')],
    timeout=30,
    max_retries=3,
    retry_on_timeout=True
)

PRODUCTS_INDEX = os.getenv('PRODUCTS_INDEX', 'products')
DEFAULT_PAGE_SIZE = 20
MAX_PAGE_SIZE = 100

def cache_response(timeout=300):
    def decorator(f):
        cache = {}
        cache_times = {}
        
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = request.full_path
            current_time = time.time()
            
            if cache_key in cache and current_time - cache_times.get(cache_key, 0) < timeout:
                return cache[cache_key]
            
            response = f(*args, **kwargs)
            cache[cache_key] = response
            cache_times[cache_key] = current_time
            
            if len(cache) > 1000:
                oldest_key = min(cache_times, key=cache_times.get)
                del cache[oldest_key]
                del cache_times[oldest_key]
            
            return response
        
        return decorated_function
    return decorator


@app.route('/api/search', methods=['GET'])
@cache_response(timeout=300)
def search_products():
    keyword = request.args.get('q', '').strip()
    page = request.args.get('page', 1, type=int)
    page_size = min(request.args.get('size', DEFAULT_PAGE_SIZE, type=int), MAX_PAGE_SIZE)
    
    if not keyword:
        return jsonify({
            'error': 'Search keyword is required',
            'message': 'Please provide a search query using the q parameter'
        }), 400
    
    if page < 1:
        page = 1
    
    from_index = (page - 1) * page_size
    
    try:
        query = {
            'query': {
                'multi_match': {
                    'query': keyword,
                    'fields': [
                        'name^3',
                        'description^2',
                        'category',
                        'brand^2',
                        'tags',
                        'sku'
                    ],
                    'type': 'best_fields',
                    'fuzziness': 'AUTO',
                    'prefix_length': 2
                }
            },
            'highlight': {
                'fields': {
                    'name': {},
                    'description': {}
                },
                'pre_tags': ['<strong>'],
                'post_tags': ['</strong>']
            },
            'from': from_index,
            'size': page_size,
            'track_total_hits': True
        }
        
        sort_by = request.args.get('sort', 'relevance')
        if sort_by == 'price_asc':
            query['sort'] = [{'price': 'asc'}]
        elif sort_by == 'price_desc':
            query['sort'] = [{'price': 'desc'}]
        elif sort_by == 'name':
            query['sort'] = [{'name.keyword': 'asc'}]
        
        filters = []
        
        min_price = request.args.get('min_price', type=float)
        max_price = request.args.get('max_price', type=float)
        if min_price is not None or max_price is not None:
            price_filter = {'range': {'price': {}}}
            if min_price is not None:
                price_filter['range']['price']['gte'] = min_price
            if max_price is not None:
                price_filter['range']['price']['lte'] = max_price
            filters.append(price_filter)
        
        category = request.args.get('category')
        if category:
            filters.append({'term': {'category.keyword': category}})
        
        brand = request.args.get('brand')
        if brand:
            filters.append({'term': {'brand.keyword': brand}})
        
        in_stock = request.args.get('in_stock')
        if in_stock and in_stock.lower() == 'true':
            filters.append({'range': {'stock': {'gt': 0}}})
        
        if filters:
            query['query'] = {
                'bool': {
                    'must': query['query'],
                    'filter': filters
                }
            }
        
        response = es.search(
            index=PRODUCTS_INDEX,
            body=query
        )
        
        products = []
        for hit in response['hits']['hits']:
            product = hit['_source']
            product['id'] = hit['_id']
            product['score'] = hit['_score']
            
            if 'highlight' in hit:
                product['highlight'] = hit['highlight']
            
            products.append(product)
        
        total = response['hits']['total']['value']
        total_pages = (total + page_size - 1) // page_size
        
        result = {
            'success': True,
            'query': keyword,
            'total': total,
            'page': page,
            'page_size': page_size,
            'total_pages': total_pages,
            'has_next': page < total_pages,
            'has_prev': page > 1,
            'products': products,
            'took': response['took']
        }
        
        return jsonify(result), 200
        
    except Exception as e:
        app.logger.error(f'Search error: {str(e)}')
        return jsonify({
            'success': False,
            'error': 'Search failed',
            'message': 'An error occurred while searching for products'
        }), 500


@app.route('/api/search/suggest', methods=['GET'])
@cache_response(timeout=600)
def search_suggestions():
    keyword = request.args.get('q', '').strip()
    
    if not keyword or len(keyword) < 2:
        return jsonify({
            'suggestions': []
        }), 200
    
    try:
        query = {
            'suggest': {
                'product-suggest': {
                    'prefix': keyword,
                    'completion': {
                        'field': 'name_suggest',
                        'size': 10,
                        'skip_duplicates': True
                    }
                }
            }
        }
        
        response = es.search(
            index=PRODUCTS_INDEX,
            body=query
        )
        
        suggestions = []
        if 'suggest' in response and 'product-suggest' in response['suggest']:
            for option in response['suggest']['product-suggest'][0]['options']:
                suggestions.append({
                    'text': option['text'],
                    'score': option['_score']
                })
        
        return jsonify({
            'suggestions': suggestions
        }), 200
        
    except Exception as e:
        app.logger.error(f'Suggestion error: {str(e)}')
        return jsonify({
            'suggestions': []
        }), 200


@app.route('/health', methods=['GET'])
def health_check():
    try:
        es.cluster.health()
        return jsonify({
            'status': 'healthy',
            'elasticsearch': 'connected'
        }), 200
    except Exception as e:
        return jsonify({
            'status': 'unhealthy',
            'elasticsearch': 'disconnected',
            'error': str(e)
        }), 503


if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, threaded=True)